    else if (bM[2]==='k'||bM[2]==='mille') critBudget*=1000;
  }
  var bD=q.match(/\b(\d{5,})\b/);
  if (bD && !critBudget) critBudget=parseInt(bD[1]);

  var scored = biens.map(function(b) {
    var score = 0;
    var bText = [b.type_de_bien,b.commune,b.quartier,b.zone_geographique,b.caracteristiques]
      .filter(Boolean).join(' ').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');
    var bLoc = [b.commune,b.quartier,b.zone_geographique].filter(Boolean).join(' ')
      .toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');

    if (critCommune && COMMUNES[critCommune] && COMMUNES[critCommune].some(function(v){return bLoc.includes(v);})) score+=40;
    if (critType && TYPES[critType]) {
      var bT=(b.type_de_bien||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');
      if (TYPES[critType].some(function(v){return bT.includes(v);})||bT.includes(critType)) score+=40;
    }
    if (critOffre) {
      var bO=(b.type_offre||'').toLowerCase();
      if (bO.includes(critOffre)) score+=25; else score-=20;
    }
    if (critMeuble) {
      if (['oui','true'].includes(String(b.meubles||'').toLowerCase())) score+=20; else score-=10;
    }
    if (critChambres>0) {
      var nb=parseInt(b.chambre);
      if (!isNaN(nb)) { if(nb===critChambres)score+=25; else if(Math.abs(nb-critChambres)===1)score+=10; else score-=15; }
    }
    if (critBudget>0) {
      var pN=parseInt(String(b.prix||'').replace(/[^0-9]/g,''));
      if (pN>0) {
        var r=pN/critBudget;
        if(r<=1.0)score+=20; else if(r<=1.2)score+=10; else if(r<=1.5)score-=10; else score-=30;
      }
    }
    for (var qi=0;qi<QUARTIERS.length;qi++) {
      var qN=QUARTIERS[qi].normalize('NFD').replace(/[\u0300-\u036f]/g,'');
      if (q.includes(qN)&&qN.length>3&&bText.includes(qN)){score+=15;break;}
    }
    q.split(/\s+/).filter(function(w){return w.length>4;}).forEach(function(w){if(bText.includes(w))score+=3;});
    return {b:b,score:score};
  });

  scored.sort(function(a,b){return b.score-a.score;});
  var top = scored.filter(function(r){return r.score>0;});

  if (top.length===0) {
    var alt = scored.slice(0,2);
    return 'AUCUN_EXACT pour "'+query+'". ALTERNATIVES_PROCHES:\n' + formaterListe(alt.map(function(r){return r.b;}));
  }

  // Dedup: telephone | type | chambre | prix arrondi (1 chiffre significatif)
  // Resiste aux extractions commune/quartier/prix incoherentes de l'IA
  var seenDedup = {};
  top = top.filter(function(r) {
    var b = r.b;
    var tel = (b.telephone_bien || b.telephone_expediteur || b.telephone || '').replace(/[^0-9]/g,'').slice(-8);
    var type5 = (b.type_de_bien || '').toLowerCase().split(' ')[0].substring(0,5);
    var ch = (b.chambre || '').replace(/[^0-9]/g,'');
    var p = parseInt((b.prix||'').replace(/[^0-9]/g,'')) || 0;
    var pBucket = p > 0 ? String(Math.round(p / Math.pow(10, Math.floor(Math.log10(p)))) * Math.pow(10, Math.floor(Math.log10(p)))) : '0';
    var key = [tel, type5, ch, pBucket].join('|');
    if (seenDedup[key]) return false;
    seenDedup[key] = true;
    return true;
  });
  var res = top.slice(0,3).map(function(r){return r.b;});
  var prefix = top.length + ' correspondance(s) sur ' + total + ' biens disponibles:\n';
  if (res.length===1) return prefix + formaterDetail(res[0]);
  return prefix + formaterListe(res);

} catch(e) {
  console.log('Erreur outil:', e.message);
  return 'Donnees indisponibles momentanement.';
}

function formaterDetail(b) {
  var m=['oui','true'].includes(String(b.meubles||'').toLowerCase());
  var lieu=[b.commune,b.quartier,b.zone_geographique].filter(Boolean).join(', ')||'Non precise';
  var tel=b.telephone_bien||b.telephone||b.telephone_expediteur||'Contactez agence';
  var surface=b.surface?'Surface: '+b.surface+'\n':'';
  var chambres=b.chambre?b.chambre+' piece(s)':'';
  var meuble=m?', meuble':'';
  return 'Type: '+(b.type_de_bien||'Bien')+' | '+(b.type_offre||'')+'\nLocalisation: '+lieu+'\nPrix: '+(b.prix||'Non communique')+'\n'+(chambres?chambres+meuble+'\n':'')+surface+(b.caracteristiques?'Details: '+b.caracteristiques.substring(0,200)+'\n':'')+'Contact: '+tel;
}

function formaterListe(biens) {
  return biens.map(function(b,i){
    var m=['oui','true'].includes(String(b.meubles||'').toLowerCase());
    var lieu=[b.commune,b.quartier].filter(Boolean).join(', ')||'N/A';
    var tel=b.telephone_bien||b.telephone||b.telephone_expediteur||'Agence';
    var chambres=b.chambre?b.chambre+'p.':'';
    return (i+1)+'. '+(b.type_de_bien||'Bien')+(m?' meuble':'')+' a '+lieu+'\n   Prix: '+(b.prix||'N/A')+(chambres?' | '+chambres:'')+'\n   Contact: '+tel;
  }).join('\n---\n');
}
